class Solution {
public:
    int peopleAwareOfSecret(int n, int delay, int forget) {
        const int MOD = 1e9 + 7;
        long long dp[n + 1];
        dp[0] = 1;
        for (int i = 1; i <= n; ++i) {
            dp[i] = (dp[i - 1] + dp[max(0LL, i - delay)]) % MOD;
            if (i >= forget) {
                dp[i] = (dp[i] - dp[max(0LL, i - forget)]) % MOD;
            }
        }
        return (int)dp[n];
    }
};
